// Valida que la URL sea de Google Solar e inyecta la API key.
// La key se inyecta acá (no en el frontend) para no exponerla.
// Idempotente: si la URL ya trae ?key= la reemplaza por la actual.
const src = $input.first().json;
const body = src.body || src;
const url = body.url;
if (!url || typeof url !== 'string') {
  return [{ json: { ok: false, reason: 'invalid_input', detail: 'url requerida' } }];
}
if (!url.startsWith('https://solar.googleapis.com/')) {
  return [{ json: { ok: false, reason: 'invalid_url', detail: 'url debe ser de solar.googleapis.com' } }];
}
const safeEnv = (k) => { try { return $env[k]; } catch (_) { return null; } };
const gkey = safeEnv('GOOGLE_API_KEY');
if (!gkey) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'GOOGLE_API_KEY no configurada en n8n' } }];
}
// Quita cualquier key= existente y agrega la nuestra
const u = new URL(url);
u.searchParams.delete('key');
u.searchParams.set('key', gkey);
return [{ json: { url: u.toString() } }];

// Detecta errores del HTTP Request y los reporta con detalle.
// n8n con continueOnFail+alwaysOutputData entrega:
//   - en éxito: item.binary.data + item.json (con headers/statusCode si fullResponse)
//   - en error: item.json.error con info del fallo
const item = $input.first();
const err = item.json?.error;
if (err) {
  return [{ json: {
    ok: false,
    reason: 'fetch_error',
    detail: `${err.statusCode || ''} ${err.message || err.description || JSON.stringify(err).slice(0,200)}`.trim(),
  } }];
}
const statusCode = item.json?.statusCode;
if (statusCode && statusCode >= 400) {
  return [{ json: {
    ok: false,
    reason: 'http_error',
    detail: `Google respondió HTTP ${statusCode}. Verifica que la API key permita geoTiff:get desde la IP de n8n (sin restricción de referer/IP).`,
  } }];
}
const bin = item.binary?.data;
if (!bin || !bin.data) {
  return [{ json: {
    ok: false,
    reason: 'no_binary',
    detail: `Sin contenido binario. statusCode=${statusCode || 'n/a'}, headers=${JSON.stringify(item.json?.headers || {}).slice(0,150)}`,
  } }];
}
return [{ json: {
  ok: true,
  base64: bin.data,
  mimeType: bin.mimeType || 'image/tiff',
  size: Number(bin.fileSize) || null,
} }];
